                                        <div className="ef-dashboard-club-facility__info">Cap: {stadiumInfo.capacity.toLocaleString()} • R$ {stadiumInfo.ticketPrice}/ingresso</div>
                                        <div className="ef-progress ef-progress--sm ef-dashboard-progress--mb">
