                            <div className="flex items-center gap-2 border-b-2 border-outline-variant pb-2 mb-4">
                                <Strategy aria-hidden="true" size={24} className="text-info" />
                                <h3 className="font-label-caps text-info">FORMAÇÃO</h3>
